def split_values(value):
    if not value:
        return []

    text = (value or '').replace('|||', '\n').replace(',', '\n')
    return [part.strip() for part in text.splitlines() if part.strip()]


def normalize(value):
    return (value or '').strip().lower()


def get_defined_options(question):
    if (question.answer_options or '').strip():
        return [value.strip() for value in question.answer_options.splitlines() if value.strip()]

    return [value.strip() for value in [question.option_a, question.option_b, question.option_c, question.option_d] if value]


def get_option_lookup(question):
    options = get_defined_options(question)
    lookup = {}

    for index, option in enumerate(options):
        normalized_option = normalize(option)
        lookup[normalized_option] = option
        if index < 26:
            lookup[chr(ord('a') + index)] = option

    return lookup


def resolve_answers(question, raw_value):
    lookup = get_option_lookup(question)
    resolved = []

    for answer in split_values(raw_value):
        resolved.append(lookup.get(normalize(answer), answer.strip()))

    return resolved


def get_correct_answers(question):
    return resolve_answers(question, question.correct_answer)


def is_correct_response(question, selected_answer):
    question_type = question.question_type or 'Single Select'
    correct_answers = get_correct_answers(question)

    if question_type == 'Open Ended':
        return None

    if question_type == 'Multi Select':
        selected_values = {normalize(value) for value in resolve_answers(question, selected_answer)}
        correct_values = {normalize(value) for value in correct_answers}
        return bool(correct_values) and selected_values == correct_values

    normalized_selected = normalize(resolve_answers(question, selected_answer)[0] if split_values(selected_answer) else '')
    return normalized_selected in {normalize(value) for value in correct_answers}


def before_submit(doc, method):
    correct = 0
    total = len(doc.answers)
    gradable_total = 0
    has_pending_review = False

    for row in doc.answers:
        question = frappe.get_doc('Quiz Question', row.question)
        question_type = question.question_type or 'Single Select'
        correct_answers = get_correct_answers(question)
        normalized_selected_answers = resolve_answers(question, row.selected_answer)
        is_correct = is_correct_response(question, row.selected_answer)

        row.question_text = question.question
        row.question_type = question_type
        row.selected_answer = '\n'.join(normalized_selected_answers)
        row.correct_answer = '\n'.join(correct_answers)

        if is_correct is None:
            row.is_correct = 0
            has_pending_review = True
        else:
            row.is_correct = 1 if is_correct else 0
            gradable_total += 1
            if row.is_correct:
                correct += 1

    doc.total_questions = total
    doc.correct_answers = correct
    doc.score_ = round((correct / gradable_total) * 100, 2) if gradable_total > 0 else 0

    quiz = frappe.get_doc('Quiz', doc.quiz)
    passing_score = quiz.passing_score_ or 70

    if has_pending_review:
        doc.passed = 0
        doc.result = 'Pending Review'
    elif doc.score_ >= passing_score:
        doc.passed = 1
        doc.result = 'Pass'
    else:
        doc.passed = 0
        doc.result = 'Fail'
